// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // Get weather icon/emoji based on condition
  const getWeatherIcon = (condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('wind')) return '🌬️';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    if (conditionLower.includes('thunder') || conditionLower.includes('storm')) return '⛈️';
    return '🌤️';
  };

  const weatherIcon = getWeatherIcon(props.condition);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        {/* Header with city name */}
        <Heading level={1} color="var(--ggui-color-onSurface)">{props.city}</Heading>

        {/* Main weather card */}
        <Card shadow="md" padding="var(--ggui-spacing-8)" radius="lg" style={{ width: '100%', maxWidth: '500px' }}>
          <Stack gap="var(--ggui-spacing-6)" align="center">
            {/* Current temperature and condition */}
            <Stack gap="var(--ggui-spacing-4)" align="center">
              {/* Large temperature display */}
              <div style={{
                display: 'flex',
                alignItems: 'baseline',
                gap: 'var(--ggui-spacing-2)',
              }}>
                <Heading level={1} style={{
                  fontSize: '72px',
                  fontWeight: 'var(--ggui-font-weight-bold)',
                  color: 'var(--ggui-color-primary-600)',
                  lineHeight: '1',
                }}>
                  {props.temperature}
                </Heading>
                <Text size="2xl" weight="semibold" color="var(--ggui-color-onSurfaceVariant)">
                  °{props.unit}
                </Text>
              </div>

              {/* Weather condition with icon */}
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Icon name={weatherIcon} size={32} />
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">
                  {props.condition}
                </Text>
              </Stack>
            </Stack>

            <Divider margin="var(--ggui-spacing-4)" />

            {/* Humidity and Wind Speed */}
            <Row gap="var(--ggui-spacing-8)" justify="center" align="center">
              {/* Humidity */}
              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Icon name="droplet" size={20} color="var(--ggui-color-primary-500)" />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Humidity
                </Text>
                <Text weight="semibold" color="var(--ggui-color-onSurface)">
                  {props.humidity}%
                </Text>
              </Stack>

              {/* Wind Speed */}
              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Icon name="wind" size={20} color="var(--ggui-color-primary-500)" />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Wind Speed
                </Text>
                <Text weight="semibold" color="var(--ggui-color-onSurface)">
                  {props.windSpeed} km/h
                </Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-day forecast section */}
        {props.forecast && props.forecast.length > 0 && (
          <Stack gap="var(--ggui-spacing-4)" style={{ width: '100%' }}>
            <Heading level={3} color="var(--ggui-color-onSurface)">
              5-Day Forecast
            </Heading>

            {/* Horizontal forecast strip */}
            <Row gap="var(--ggui-spacing-3)" wrap style={{
              overflowX: 'auto',
              paddingBottom: 'var(--ggui-spacing-2)',
            }}>
              {props.forecast.map((day, index) => (
                <Card
                  key={index}
                  shadow="sm"
                  padding="var(--ggui-spacing-4)"
                  radius="md"
                  style={{
                    flex: '0 0 auto',
                    minWidth: '120px',
                    textAlign: 'center',
                    backgroundColor: 'var(--ggui-color-surfaceVariant)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2)" align="center">
                    {/* Day name */}
                    {day.day && (
                      <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
                        {day.day}
                      </Text>
                    )}

                    {/* Weather icon */}
                    {day.icon && (
                      <Icon name={day.icon} size={24} />
                    )}

                    {/* High/Low temps */}
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                      {day.high !== undefined && (
                        <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-primary-600)">
                          {day.high}°
                        </Text>
                      )}
                      {day.low !== undefined && (
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                          {day.low}°
                        </Text>
                      )}
                    </Stack>
                  </Stack>
                </Card>
              ))}
            </Row>
          </Stack>
        )}
      </Stack>
    </Container>
  );
}
}

