  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





export default function Component(props: Props) {
  // State for search and selected element
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<(typeof props.elements)[0] | null>(null);

  // Filter elements by name or symbol (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el => 
      (el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories and assign colors
  const categoryColors: Record<string, string> = useMemo(() => {
    const categories = [...new Set(props.elements.map(el => el.category).filter(Boolean))];
    const colorMap: Record<string, string> = {
      'noble-gas': 'var(--ggui-color-primary-100, #e0f2fe)',
      'halogen': 'var(--ggui-color-warning-100, #fef3c7)',
      'alkali-metal': 'var(--ggui-color-error-100, #fee2e2)',
      'alkaline-earth-metal': 'var(--ggui-color-success-100, #dcfce7)',
      'transition-metal': 'var(--ggui-color-info-100, #cffafe)',
      'lanthanide': 'var(--ggui-color-primary-50, #f0f9ff)',
      'actinide': 'var(--ggui-color-primary-100, #e0f2fe)',
      'metalloid': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
      'nonmetal': 'var(--ggui-color-success-50, #f0fdf4)',
      'other-metal': 'var(--ggui-color-warning-50, #fffbeb)',
    };
    return colorMap;
  }, [props.elements]);

  // Build category to color mapping with fallbacks
  const getElementColor = (category?: string): string => {
    if (!category) return 'var(--ggui-color-surface, #ffffff)';
    return categoryColors[category] || 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  };

  // Get unique categories for legend
  const uniqueCategories = useMemo(() => {
    const categories = new Set(props.elements.map(el => el.category).filter(Boolean));
    return Array.from(categories).sort();
  }, [props.elements]);

  return (
    <Stack gap="var(--ggui-spacing-6)" direction="vertical">
      {/* Header */}
      <Stack gap="var(--ggui-spacing-4)" direction="vertical">
        <Heading level={1} color="var(--ggui-color-onSurface)">Periodic Table of Elements</Heading>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
          Interactive periodic table with {props.elements.length} elements. Click any element for details.
        </Text>
      </Stack>

      {/* Search input */}
      <SearchField
        value={searchQuery}
        onChange={setSearchQuery}
        placeholder="Search by name or symbol.."
        size="md"
      />

      {/* Legend */}
      <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
        <Stack gap="var(--ggui-spacing-2)" direction="vertical">
          <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
            Legend
          </Text>
          <Stack gap="var(--ggui-spacing-4)" direction="horizontal" wrap>
            {uniqueCategories.map(cat => (
              <Stack key={cat} gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
                <Box
                  background={getElementColor(cat)}
                  borderRadius="4px"
                  style={{
                    width: '20px',
                    height: '20px',
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  }}
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                  {cat?.split('-').join(' ') || 'Unknown'}
                </Text>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Card>

      {/* Periodic table grid */}
      <Box
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, 1fr)',
          gap: 'var(--ggui-spacing-2, 8px)',
          padding: 'var(--ggui-spacing-4, 16px)',
          backgroundColor: 'var(--ggui-color-surface, #ffffff)',
          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
          border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          minHeight: '500px',
        }}
      >
        {filteredElements.map((element) => {
          const row = element.row || 1;
          const col = element.col || 1;
          const isSelected = selectedElement?.atomicNumber === element.atomicNumber;

          return (
            <Card
              key={element.atomicNumber || Math.random()}
              as={Clickable}
              onClick={() => setSelectedElement(element)}
              padding="var(--ggui-spacing-2)"
              shadow="sm"
              radius="md"
              border
              style={{
                gridRow: row,
                gridColumn: col,
                background: getElementColor(element.category),
                cursor: 'pointer',
                border: isSelected ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid var(--ggui-color-outline, #d4d4d8)',
                transition: 'all 200ms ease-in-out',
                transform: isSelected ? 'scale(1.05)' : 'scale(1)',
              }}
              hoverStyle={{
                boxShadow: 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))',
                transform: 'scale(1.02)',
              }}
            >
              <Stack gap="var(--ggui-spacing-1)" direction="vertical" align="center">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant)"
                  size="xs"
                  align="left"
                  style={{ alignSelf: 'flex-start' }}
                >
                  {element.atomicNumber}
                </Text>
                <Text
                  variant="label"
                  weight="bold"
                  color="var(--ggui-color-onSurface)"
                  size="lg"
                  align="center"
                >
                  {element.symbol}
                </Text>
              </Stack>
            </Card>
          );
        })}
      </Box>

      {/* Details panel */}
      {selectedElement && (
        <Card padding="var(--ggui-spacing-6)" shadow="md" border>
          <Stack gap="var(--ggui-spacing-4)" direction="vertical">
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center" justify="between">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                {selectedElement.name || 'Unknown Element'}
              </Heading>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setSelectedElement(null)}
              >
                ✕
              </Button>
            </Stack>

            <Stack gap="var(--ggui-spacing-3)" direction="vertical">
              <Stack gap="var(--ggui-spacing-4)" direction="horizontal" wrap>
                <Stack gap="var(--ggui-spacing-2)" direction="vertical" style={{ flex: 1, minWidth: '200px' }}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" weight="medium">
                    Symbol
                  </Text>
                  <Badge variant="primary" size="lg">
                    {selectedElement.symbol || 'N/A'}
                  </Badge>
                </Stack>

                <Stack gap="var(--ggui-spacing-2)" direction="vertical" style={{ flex: 1, minWidth: '200px' }}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" weight="medium">
                    Atomic Number
                  </Text>
                  <Text variant="body" size="lg" weight="bold" color="var(--ggui-color-primary-600)">
                    {selectedElement.atomicNumber || 'N/A'}
                  </Text>
                </Stack>

                <Stack gap="var(--ggui-spacing-2)" direction="vertical" style={{ flex: 1, minWidth: '200px' }}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" weight="medium">
                    Atomic Weight
                  </Text>
                  <Text variant="body" size="lg" weight="bold" color="var(--ggui-color-primary-600)">
                    {selectedElement.atomicWeight?.toFixed(3) || 'N/A'}
                  </Text>
                </Stack>
              </Stack>

              <Stack gap="var(--ggui-spacing-2)" direction="vertical">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" weight="medium">
                  Category
                </Text>
                <Box
                  background={getElementColor(selectedElement.category)}
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  padding="var(--ggui-spacing-2)"
                  style={{
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Text variant="body" color="var(--ggui-color-onSurface)" weight="medium">
                    {selectedElement.category?.split('-').join(' ') || 'Unknown'}
                  </Text>
                </Box>
              </Stack>
            </Stack>
          </Stack>
        </Card>
      )}

      {/* Empty state */}
      {filteredElements.length === 0 && (
        <Card padding="var(--ggui-spacing-8)" shadow="sm" border>
          <Stack gap="var(--ggui-spacing-4)" direction="vertical" align="center" justify="center">
            <Icon name="search" size={48} color="var(--ggui-color-outline)" />
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
              No elements found matching "{searchQuery}"
            </Text>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}
}

