            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">{props.product.name || 'Product Name'}</Heading>

            {/* Price */}
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
              {formattedPrice}
            </Text>

            {/* Rating */}
            <Row align="center" gap="var(--ggui-spacing-2)">
              {renderRatingStars(props.product.rating)}
            </Row>

            {/* Stock Badge */}
            <Badge variant={stockBadgeVariant}>{stockBadgeText}</Badge>
          </Stack>
        </Stack>

        {/* Middle Section: Tab Navigation */}
        <Stack gap="var(--ggui-spacing-4)" align="stretch">
          <Tabs
            items={tabItems}
            activeKey={selectedTab}
            onChange={setSelectedTab}
            variant="line"
            size="md"
          />
        </Stack>

        {/* Bottom Section: Quantity & Add to Cart */}
        {/* Bottom Section: Quantity & Add to Cart */}
        <Stack
          gap="var(--ggui-spacing-4)"
          direction="horizontal"
          align="center"
          style={{
            flexDirection: 'column',
            '@media (min-width: 640px)': {
              flexDirection: 'row',
            },
          }}
        >
          {/* Quantity Selector */}
          <Stack gap="var(--ggui-spacing-2)" align="center">
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Quantity:
            </Text>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Button
                variant="secondary"
                size="sm"
                onClick={() => handleQuantityChange(quantity - 1)}
                disabled={quantity <= 1}
              >
                −
              </Button>
              <Text variant="label" style={{ minWidth: '40px', textAlign: 'center' }}>
                {quantity}
              </Text>
              <Button
                variant="secondary"
                size="sm"
                onClick={() => handleQuantityChange(quantity + 1)}
                disabled={quantity >= maxQuantity}
              >
                +
              </Button>
            </Row>
          </Stack>

          <Spacer size="flex" />

          {/* Add to Cart Button */}
          <Button
            variant="primary"
            size="lg"
            onClick={handleAddToCart}
            disabled={isOutOfStock}
            style={{
              width: '100%',
              '@media (min-width: 640px)': {
                width: 'auto',
              },
            }}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

