interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State for messages and input
  const [messages, setMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  const [typingIndicator, setTypingIndicator] = useState<{ sender?: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Scroll to bottom whenever messages change
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  // Handle new messages from stream
  useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setTypingIndicator({ sender: typing.latest.sender });
      } else {
        setTypingIndicator(null);
      }
    }
  }, [typing.latest]);

  // Handle sending a message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  // Handle Enter key to send message
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Format timestamp for display
  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  // Group consecutive messages from the same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    messages.forEach((msg) => {
      if (groups.length === 0 || groups[groups.length - 1].sender !== msg.sender) {
        groups.push({ sender: msg.sender, messages: [msg] });
      } else {
        groups[groups.length - 1].messages.push(msg);
      }
    });

    return groups;
  }, [messages]);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" radius="lg" padding="0">
        <Stack gap="0" direction="vertical">
          {/* Header */}
          <Box paddingX="var(--ggui-spacing-6)" paddingY="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="var(--ggui-shape-radius-lg, 12px)">
            <Stack direction="horizontal" align="center" justify="between" gap="var(--ggui-spacing-4)">
              <Stack direction="vertical" gap="var(--ggui-spacing-1)">
                <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">{props.title}</Heading>
              </Stack>
              <Badge variant="primary" size="md">{props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}</Badge>
            </Stack>
          </Box>

          <Divider margin="0" />

          {/* Message list */}
          <Box paddingX="var(--ggui-spacing-6)" paddingY="var(--ggui-spacing-4)" background="var(--ggui-color-surface, #fafafa)" borderRadius="0">
            <Stack gap="var(--ggui-spacing-4)" direction="vertical" align="stretch">
              {groupedMessages.length === 0 ? (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                  No messages yet. Start the conversation!
                </Text>
              ) : (
                groupedMessages.map((group, groupIndex) => {
                  const isCurrentUser = group.sender === props.currentUser;
                  return (
                    <Stack
                      key={groupIndex}
                      gap="var(--ggui-spacing-2)"
                      direction="vertical"
                      align={isCurrentUser ? 'end' : 'start'}
                    >
                      {group.messages.map((msg, msgIndex) => (
                        <Stack key={msgIndex} gap="var(--ggui-spacing-2)" direction="horizontal" align="end">
                          {!isCurrentUser && msgIndex === 0 && (
                            <Box paddingX="var(--ggui-spacing-1)" style={{ minWidth: '28px' }}>
                              <Avatar name={group.sender || 'Unknown'} size="sm" />
                            </Box>
                          )}
                          {!isCurrentUser && msgIndex > 0 && (
                            <Box paddingX="var(--ggui-spacing-1)" style={{ minWidth: '28px' }} />
                          )}
                          <Box
                            paddingX="var(--ggui-spacing-4)"
                            paddingY="var(--ggui-spacing-2)"
                            background={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-600, #0284c7)'
                                : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                            }
                            borderRadius="var(--ggui-shape-radius-md, 8px)"
                            style={{ maxWidth: '70%', wordWrap: 'break-word' }}
                          >
                            <Text
                              variant="body"
                              color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                            >
                              {msg.text}
                            </Text>
                            {msgIndex === group.messages.length - 1 && (
                              <Text
                                variant="caption"
                                color={isCurrentUser ? 'rgba(255,255,255,0.8)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                                align="right"
                                style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
                              >
                                {formatTime(msg.timestamp)}
                              </Text>
                            )}
                          </Box>
                        </Stack>
                       ))}
                     </Stack>
                   );
                 })
              )}

               {/* Typing indicator */}
               {typingIndicator && (
                 <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
                   <Box paddingX="var(--ggui-spacing-1)" style={{ minWidth: '28px' }}>
                     <Avatar name={typingIndicator.sender || 'User'} size="sm" />
                   </Box>
                   <Box
                     paddingX="var(--ggui-spacing-4)"
                     paddingY="var(--ggui-spacing-2)"
                     background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                     borderRadius="var(--ggui-shape-radius-md, 8px)"
                   >
                     <Stack direction="horizontal" gap="var(--ggui-spacing-1)" align="center">
                       <Spinner size={12} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                       <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                         {typingIndicator.sender || 'Someone'} is typing...
                       </Text>
                     </Stack>
                   </Box>
                 </Stack>
               )}

               {/* Scroll anchor */}
               <div ref={messagesEndRef} />
             </Stack>
           </Box>

           <Divider margin="0" />

           {/* Input area */}
            <Box paddingX="var(--ggui-spacing-6)" paddingY="var(--ggui-spacing-4)">
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="end">
                <TextArea
                  label="Message input"
                  placeholder="Type your message...(Shift+Enter for new line)"
                  value={inputValue}
                  onChange={setInputValue}
                  onKeyDown={handleKeyDown}
                  rows={3}
                  style={{ flex: 1, display: 'block' }}
                />
                <Button
                  variant="primary"
                  size="md"
                  onClick={handleSendMessage}
                  disabled={!inputValue.trim()}
                >
                  Send
                </Button>
              </Stack>
            </Box>
        </Stack>
      </Card>
    </Container>
  );
}

