// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State: stock data with live updates merged in
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [highlightedSymbol, setHighlightedSymbol] = useState<string | null>(null);

  // Merge live price updates into stock data
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prevStocks) => {
        const updated = prevStocks.map((stock) => {
          if (stock.symbol === update.symbol) {
            // Highlight the updated stock briefly
            setHighlightedSymbol(update.symbol);
            setTimeout(() => setHighlightedSymbol(null), 500);
            // Return updated stock data
            return {
              ...stock,
              price: update.price ?? stock.price,
              change: update.change ?? stock.change,
              changePercent: update.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
        return updated;
      });
      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  // Determine market status text and styling
  const marketStatusText = useMemo(() => {
    if (!marketStatus.latest?.status) return 'Market Status Unknown';
    const status = marketStatus.latest.status;
    return status.charAt(0).toUpperCase() + status.slice(1).replace('-', ' ');
  }, [marketStatus.latest?.status]);

  const statusVariant = useMemo(() => {
    switch (marketStatus.latest?.status) {
      case 'open':
        return 'success' as const;
      case 'closed':
        return 'default' as const;
      case 'pre-market':
        return 'warning' as const;
      case 'after-hours':
        return 'info' as const;
      default:
        return 'default' as const;
    }
  }, [marketStatus.latest?.status]);

  // Format number with 2 decimal places
  const formatPrice = (value?: number): string => {
    if (value === undefined || value === null) return '-';
    return value.toFixed(2);
  };

  const formatTime = (date: Date): string => {
    return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" direction="vertical">
        {/* Header Section */}
        <Box
          paddingY="var(--ggui-spacing-4)"
          background="var(--ggui-color-primary-50, #f0f9ff)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
          paddingX="var(--ggui-spacing-6)"
        >
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="vertical" gap="var(--ggui-spacing-1)">
              <Heading level={1} color="var(--ggui-color-primary-900, #0c4a6e)">
                Market Watch
              </Heading>
              <Text
                variant="bodySmall"
                color="var(--ggui-color-primary-700, #0369a1)"
              >
                Last Updated: {formatTime(lastUpdated)}
              </Text>
            </Stack>
            <Badge variant={statusVariant} size="md" pill>
              {marketStatusText}
            </Badge>
          </Stack>
        </Box>

        {/* Stock Cards Grid */}
        {stocks && stocks.length > 0 ? (
          <>
            <style>{`
              .stock-grid {
                display: grid;
                grid-template-columns: repeat(3, 1fr);
                gap: var(--ggui-spacing-6);
              }
              @media (max-width: 768px) {
                .stock-grid {
                  grid-template-columns: 1fr;
                }
              }
              @keyframes highlight-flash {
                0% { background-color: rgba(22, 163, 74, 0.1); }
                100% { background-color: transparent; }
              }
              @keyframes highlight-flash-error {
                0% { background-color: rgba(220, 38, 38, 0.1); }
                100% { background-color: transparent; }
              }
            `}</style>
            <div className="stock-grid">
              {stocks.map((stock) => {
                const isPositive = (stock.changePercent ?? 0) >= 0;
                const isHighlighted = highlightedSymbol === stock.symbol;
                const changeColor = isPositive
                  ? 'var(--ggui-color-success-600, #16a34a)'
                  : 'var(--ggui-color-error-600, #dc2626)';
                const arrowIcon = isPositive ? '▲' : '▼';

                return (
                  <Card
                    key={stock.symbol}
                    padding="var(--ggui-spacing-4)"
                    shadow="md"
                    radius="lg"
                    border={true}
                    style={{
                      borderColor: isHighlighted
                        ? changeColor
                        : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                      borderWidth: isHighlighted ? '2px' : '1px',
                      transition: 'all 300ms ease-out',
                      animation: isHighlighted
                        ? `highlight-flash${isPositive ? '' : '-error'} 500ms ease-out`
                        : 'none',
                    } as any}
                  >
                    <Stack gap="var(--ggui-spacing-3)" direction="vertical">
                      {/* Ticker Symbol */}
                      <Heading
                        level={3}
                        color="var(--ggui-color-onSurface, #18181b)"
                        style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)', fontWeight: 'var(--ggui-font-weight-bold, 700)' } as any}
                      >
                        {stock.symbol || 'N/A'}
                      </Heading>

                      {/* Company Name */}
                      <Text
                        variant="bodySmall"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {stock.name || 'Unknown Company'}
                      </Text>

                      <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

                      {/* Current Price */}
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Current Price
                        </Text>
                        <Text
                          variant="body"
                          weight="bold"
                          color="var(--ggui-color-onSurface, #18181b)"
                          size="xl"
                        >
                          ${formatPrice(stock.price)}
                        </Text>
                      </Stack>

                      {/* Change Amount & Percentage */}
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Change
                        </Text>
                        <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                          <Text color={changeColor} weight="semibold">
                            {isPositive ? '+' : ''}{formatPrice(stock.change)}
                          </Text>
                          <Text color={changeColor} weight="semibold">
                            {arrowIcon} {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                          </Text>
                        </Stack>
                      </Stack>
                    </Stack>
                  </Card>
                );
              })}
            </div>
          </>
        ) : (
          <Box
            paddingY="var(--ggui-spacing-12)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-lg)"
          >
            <Text
              align="center"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              No stocks available
            </Text>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar || (props.avatarOptions.length > 0 ? props.avatarOptions[0] : ''));
  const [role, setRole] = useState(props.initialProfile.role || (props.roleOptions.length > 0 ? props.roleOptions[0] : ''));
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme || 'light');

  // Validation
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = emailRegex.test(email);
  const isStep1Valid = name.trim() !== '' && isEmailValid;
  const isStep2Valid = role !== '';
  const canProceed = currentStep === 1 ? isStep1Valid : currentStep === 2 ? isStep2Valid : true;

  // Handlers
  const handleNext = useCallback(() => {
    if (canProceed && currentStep < 3) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, canProceed]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    complete({
      name,
      email,
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [name, email, avatar, role, emailNotifications, theme, complete]);

  // Calculate progress percentage
  const progress = (currentStep / 3) * 100;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        {/* Step Indicator */}
        <Stack gap="var(--ggui-spacing-4)" style={{ width: '100%', maxWidth: '600px' }}>
          <Text variant="label" align="center"
            style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}>
            Step {currentStep} of 3
          </Text>
          <Progress
            value={progress}
            max={100}
            variant="default"
            size="md"
          />
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card
            padding="var(--ggui-spacing-6)"
            shadow="md"
            radius="lg"
            style={{ width: '100%', maxWidth: '600px' }}
          >
            <Stack gap="var(--ggui-spacing-6)" align="stretch">
              <Heading level={2} align="center">Profile Setup</Heading>
              <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Let\'s get to know you better
              </Text>

              {/* Name Input */}
              <Input
                label="Full Name"
                value={name}
                onChange={setName}
                placeholder="John Doe"
                required
              />

              {/* Email Input */}
              <Input
                label="Email Address"
                type="email"
                value={email}
                onChange={setEmail}
                placeholder="you@example.com"
                required
                error={email && !isEmailValid ? 'Please enter a valid email' : undefined}
              />

              {/* Avatar Selection */}
              <Stack gap="var(--ggui-spacing-2)" align="start">
                <Text variant="label" style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}>
                  Choose Your Avatar <span style={{ color: 'var(--ggui-color-error-500, #ef4444)' }}>*</span>
                </Text>
                <Row gap="var(--ggui-spacing-4)" wrap>
                  {props.avatarOptions.map((emojiAvatar) => (
                    <Box
                      key={emojiAvatar}
                      as={Clickable}
                      onClick={() => setAvatar(emojiAvatar)}
                      style={{
                        padding: 'var(--ggui-spacing-2)',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        border: avatar === emojiAvatar
                          ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                          : '2px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                        cursor: 'pointer',
                        transition: 'all 200ms ease-in-out',
                        fontSize: '32px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        width: '56px',
                        height: '56px',
                      }}
                    >
                      {emojiAvatar}
                    </Box>
                  ))}
                </Row>
              </Stack>

              {/* Navigation Buttons */}
              <Row gap="var(--ggui-spacing-4)" justify="end">
                <Button
                  variant="secondary"
                  onClick={handleBack}
                  disabled
                  style={{ opacity: 0.5 }}
                >
                  Go Back
                </Button>
                <Button
                  variant="primary"
                  onClick={handleNext}
                  disabled={!canProceed}
                >
                  Next
                </Button>
              </Row>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card
            padding="var(--ggui-spacing-6)"
            shadow="md"
            radius="lg"
            style={{ width: '100%', maxWidth: '600px' }}
          >
            <Stack gap="var(--ggui-spacing-6)" align="stretch">
              <Heading level={2} align="center">Preferences</Heading>
              <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Customize your experience
              </Text>

              {/* Role Selection */}
              <Select
                label="Your Role"
                value={role}
                onChange={setRole}
                options={props.roleOptions.map((r) => ({
                  value: r,
                  label: r,
                }))}
                placeholder="Select a role"
                required
              />

              {/* Email Notifications Toggle */}
              <Toggle
                label="Email Notifications"
                checked={emailNotifications}
                onChange={setEmailNotifications}
              />

              {/* Theme Preference */}
              <RadioGroup
                label="Theme Preference"
                value={theme}
                onChange={setTheme}
                options={[
                  { value: 'light', label: 'Light' },
                  { value: 'dark', label: 'Dark' },
                ]}
                direction="horizontal"
              />

              {/* Navigation Buttons */}
              <Row gap="var(--ggui-spacing-4)" justify="end">
                <Button
                  variant="secondary"
                  onClick={handleBack}
                >
                  Go Back
                </Button>
                <Button
                  variant="primary"
                  onClick={handleNext}
                  disabled={!canProceed}
                >
                  Next
                </Button>
              </Row>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card
            padding="var(--ggui-spacing-6)"
            shadow="md"
            radius="lg"
            style={{ width: '100%', maxWidth: '600px' }}
          >
            <Stack gap="var(--ggui-spacing-6)" align="stretch">
              <Heading level={2} align="center">Review & Confirm</Heading>
              <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Please verify your information
              </Text>

              {/* Summary Section */}
              <Stack gap="var(--ggui-spacing-4)" style={{
                backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                padding: 'var(--ggui-spacing-4)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              }}>
                {/* Profile Section */}
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={4}>Profile</Heading>
                  <Row gap="var(--ggui-spacing-4)" align="center">
                    <Box style={{ fontSize: '32px' }}>{avatar}</Box>
                    <Stack gap="var(--ggui-spacing-1)" align="start">
                      <Text variant="label">Name</Text>
                      <Text variant="body">{name}</Text>
                    </Stack>
                  </Row>
                  <Stack gap="var(--ggui-spacing-1)" align="start">
                    <Text variant="label">Email</Text>
                    <Text variant="body">{email}</Text>
                  </Stack>
                </Stack>

                <Divider orientation="horizontal" margin="var(--ggui-spacing-4)" />

                {/* Preferences Section */}
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={4}>Preferences</Heading>
                  <Stack gap="var(--ggui-spacing-1)" align="start">
                    <Text variant="label">Role</Text>
                    <Text variant="body">{role}</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1)" align="start">
                    <Text variant="label">Email Notifications</Text>
                    <Badge variant={emailNotifications ? 'success' : 'default'}>
                      {emailNotifications ? 'Enabled' : 'Disabled'}
                    </Badge>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1)" align="start">
                    <Text variant="label">Theme</Text>
                    <Text variant="body" style={{ textTransform: 'capitalize' }}>{theme}</Text>
                  </Stack>
                </Stack>
              </Stack>

              {/* Navigation Buttons */}
              <Row gap="var(--ggui-spacing-4)" justify="end">
                <Button
                  variant="secondary"
                  onClick={handleBack}
                >
                  Go Back
                </Button>
                <Button
                  variant="primary"
                  onClick={handleComplete}
                >
                  Complete Setup
                </Button>
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}
}
